		["BG - Arathi Basin Cap Announcer"] = {
			["outline"] = "OUTLINE",
			["wagoID"] = "4nJyhahP7",
			["xOffset"] = 0,
			["preferToUpdate"] = true,
			["shadowYOffset"] = -1,
			["anchorPoint"] = "CENTER",
			["customTextUpdate"] = "event",
			["automaticWidth"] = "Auto",
			["actions"] = {
				["start"] = {
				},
				["init"] = {
					["custom"] = "aura_env.currtime = 0\naura_env.fivecheck = false\naura_env.fourcheck = false\naura_env.threecheck = false\naura_env.twocheck = false\naura_env.onecheck = false\naura_env.zone = nil\naura_env.chattype = \"INSTANCE_CHAT\" -- INSTANCE_CHAT for bg, otherwise SAY, RAID, EMOTE",
					["do_custom"] = true,
				},
				["finish"] = {
				},
			},
			["triggers"] = {
				{
					["trigger"] = {
						["type"] = "custom",
						["customVariables"] = "{\n    duration = true\n}",
						["subeventSuffix"] = "_CAST_START",
						["custom_hide"] = "timed",
						["custom_type"] = "status",
						["event"] = "Health",
						["names"] = {
						},
						["customDuration"] = "function()\n    return 10, aura_env.startTime\nend",
						["events"] = "UNIT_SPELLCAST_START:player, UNIT_SPELLCAST_INTERRUPTED:player",
						["custom"] = "function()\n    if aura_env.currtime > 0 then\n        local timetocap = 10 - math.floor(GetTime() - aura_env.currtime)\n        if timetocap > 0 then\n            \n            -- setting zone inside to save resources\n            local function returntext(num) \n                return \"Capping \"..aura_env.zone..\" in \"..num..\"...\"\n            end\n            \n            if timetocap == 5 and not aura_env.fivecheck then\n                aura_env.fivecheck = true\n                SendChatMessage(returntext(5), aura_env.chattype);\n            elseif timetocap == 4 and not aura_env.fourcheck then\n                aura_env.fourcheck = true\n                SendChatMessage(returntext(4), aura_env.chattype);\n            elseif timetocap == 3 and not aura_env.threecheck then\n                aura_env.threecheck = true\n                SendChatMessage(returntext(3), aura_env.chattype);\n            elseif timetocap == 2 and not aura_env.twocheck then\n                aura_env.twocheck = true\n                SendChatMessage(returntext(2), aura_env.chattype);\n            elseif timetocap == 1 and not aura_env.onecheck then\n                aura_env.onecheck = true\n                SendChatMessage(returntext(1), aura_env.chattype);\n                return true\n            end\n        end\n    end    \nend",
						["subeventPrefix"] = "SPELL",
						["check"] = "update",
						["spellIds"] = {
						},
						["unit"] = "player",
						["debuffType"] = "HELPFUL",
					},
					["untrigger"] = {
						["custom"] = "function()\n    return true\nend\n\n\n",
					},
				}, -- [1]
				{
					["trigger"] = {
						["custom_hide"] = "timed",
						["type"] = "custom",
						["custom"] = "function(e, ...)\n    \n    local function reset_auraenvs()\n        aura_env.currtime = 0\n        aura_env.fivecheck = false\n        aura_env.fourcheck = false\n        aura_env.threecheck = false\n        aura_env.twocheck = false\n        aura_env.onecheck = false\n        aura_env.zone = nil\n    end\n    \n    \n    local spellid = select(3, ...)\n    if spellid == 21651 then\n        -- Start capping\n        if e == \"UNIT_SPELLCAST_START\" then\n            aura_env.currtime = GetTime()\n            aura_env.zone = string.upper(GetSubZoneText())\n            -- Capping interrupted\n        elseif e == \"UNIT_SPELLCAST_INTERRUPTED\" then\n            if aura_env.fivecheck then\n                SendChatMessage(\"Capping \"..aura_env.zone..\" interrupted\", aura_env.chattype);\n            end\n            reset_auraenvs()\n            -- Capping succeeded\n        elseif e == \"UNIT_SPELLCAST_SUCCEEDED\" then\n            reset_auraenvs()\n        end\n        \n        -- currently capping but something happened to a flag (Potentially the one you're capping)\n    elseif (e == \"CHAT_MSG_BG_SYSTEM_HORDE\" or e == \"CHAT_MSG_BG_SYSTEM_ALLIANCE\") then\n        if aura_env.currtime > 0 and aura_env.zone ~= nil then\n            local bgmsg = select(1, ...)\n            local formatted_zone = switchcase(aura_env.zone)\n            \n            -- Something happened to the base you were capping (Meaning either it got assaulted by a teammate, an enemy or it changed to enemy faction)\n            if string.find(bgmsg, formatted_zone) ~= nil then\n                reset_auraenvs()\n            end\n        end\n    end\nend\n\n\n",
						["subeventSuffix"] = "_CAST_START",
						["events"] = "UNIT_SPELLCAST_START:player, UNIT_SPELLCAST_INTERRUPTED:player, UNIT_SPELLCAST_SUCCEEDED:player, CHAT_MSG_BG_SYSTEM_ALLIANCE, CHAT_MSG_BG_SYSTEM_HORDE, CHAT_MSG_BG_SYSTEM_NEUTRAL",
