		["Mythic+ Auto Marker"] = {
			["outline"] = "OUTLINE",
			["wagoID"] = "b_JzlxXLu",
			["color"] = {
				1, -- [1]
				1, -- [2]
				1, -- [3]
				1, -- [4]
			},
			["displayText"] = "",
			["yOffset"] = 0,
			["anchorPoint"] = "LEFT",
			["displayText_format_p_time_format"] = 0,
			["customTextUpdate"] = "event",
			["url"] = "https://wago.io/b_JzlxXLu/60",
			["actions"] = {
				["start"] = {
					["custom"] = "",
					["do_custom"] = false,
				},
				["init"] = {
					["custom"] = "-- Example on how to add aura_env table to VDT:\n-- ViragDevTool_AddData(aura_env, aura_env.id..\"-env table\")\n\n\n\naura_env.chosenMarkers1 = {}\naura_env.chosenMarkers2 = {}\naura_env.chosenMarkers3 = {}\n\n-- Populate the markers lists\nfor i = 1, 3 do\n    for y = 1, 8 do\n        if aura_env.config.markers[\"markersGroup\"..i..\"-\"..y] then\n            aura_env[\"chosenMarkers\"..i][y] = true\n        end\n    end\nend\n\n-- Checks if unit is marked and adds it to the used markers table if so\nlocal function AddMarkedUnitToUsedMarkers(unit)\n    if (GetRaidTargetIndex(unit)) then\n        aura_env.usedMarkers[GetRaidTargetIndex(unit)] = true\n    end\nend\n\n-- Populate the enemies list\nfunction aura_env.UpdateTables()\n    aura_env.enemies = {}\n    \n    local instanceId, _ = select(8,GetInstanceInfo())\n    \n    -- Seasonal mobs\n    for _, v in ipairs(aura_env.config.season) do\n        if v.shouldMark then\n            aura_env.enemies[v.npcId] = {debuff = 0, group = tonumber(v.enemyGroup)}\n        end\n    end\n    \n    -- Dungeon mobs\n    if aura_env.config[\"IID\" .. instanceId] then\n        for _, v in ipairs(aura_env.config[\"IID\" .. instanceId]) do\n            if v.shouldMark then\n                if v.npcId == \"134024\" then -- if it's a Devouring Maggot\n                    aura_env.enemies[v.npcId] = {debuff = 278431, group = tonumber(v.enemyGroup)}\n                else\n                    aura_env.enemies[v.npcId] = {debuff = 0, group = tonumber(v.enemyGroup)}\n                end\n            end\n        end\n    end\nend\n\n-- Check if you or any party member is in combat with the mob\nfunction aura_env.UnitIsInCombatWithParty(unit)\n    for partyMember in WA_IterateGroupMembers(false, true) do\n        if UnitThreatSituation(partyMember, unit) then\n            return true\n        end\n    end\n    return false\nend\n\n-- Return true if correct modifier for mouseover marking is pressed\n-- 1 = None\n-- 2 = Shift\n-- 3 = Ctrl\n-- 4 = Alt\nfunction aura_env.CheckMouseoverModifier()\n    local key = aura_env.config.mouseoverSettings.mouseoverKey\n    if key == 1 then\n        return true\n    elseif key == 2 and IsShiftKeyDown() then\n        return true\n    elseif key == 3 and IsControlKeyDown() then\n        return true\n    elseif key == 4 and IsAltKeyDown() then\n        return true\n    else\n        return false\n    end\nend\n\n-- Add enemy to the marking list if it should be marked\nfunction aura_env.SelectEnemyToMark(unit)\n    local npcId, _ = select(6, strsplit(\"-\", UnitGUID(unit)))\n    \n    if aura_env.enemies[npcId] then\n        local group = aura_env.enemies[npcId].group\n        local debuff = aura_env.enemies[npcId].debuff\n        \n        if debuff ~= 0 then \n            if WA_GetUnitBuff(unit, debuff) then\n                table.insert(aura_env[\"enemiesToMark\"..group], unit)\n            end\n        else \n            table.insert(aura_env[\"enemiesToMark\"..group], unit)\n        end \n    end\nend\n\n-- Iterate through table of enemies and put first free chosen marker on them\nfunction aura_env.MarkEnemies(chosenMarkers, enemiesToMark)\n    local startValue\n    local endValue\n    local stepValue\n    \n    if aura_env.config.markers.order == 2 then\n        startValue = 8\n        endValue = 1\n        stepValue = -1\n    else\n        startValue = 1\n        endValue = 8\n        stepValue = 1\n    end\n    \n    for i = 1, #enemiesToMark do\n        \n        for j = startValue, endValue, stepValue do\n            if aura_env.usedMarkers[j] == false and\n            chosenMarkers[j] == true and\n            not GetRaidTargetIndex(enemiesToMark[i]) then\n                SetRaidTarget(enemiesToMark[i], j)\n                aura_env.usedMarkers[j] = true\n                break\n            end\n        end\n    end\nend\n\n-- Checks player, party, boss and nameplates for used markers\nfunction aura_env.GetUsedMarkers()\n    -- Sets all markers as unused\n    for i = 1, 8 do\n        aura_env.usedMarkers[i] = false\n    end\n    \n    -- Don't use marks already used on party1-4 or player\n    for partyMember in WA_IterateGroupMembers(false, true) do\n        AddMarkedUnitToUsedMarkers(partyMember)\n    end\n    \n    -- Don't use marks already used on boss1-4\n    for i = 1, 4 do\n        AddMarkedUnitToUsedMarkers(\"boss\"..i)\n    end\n    \n    -- Don't use marks already used on nameplates\n    for i = 1, 40 do\n        AddMarkedUnitToUsedMarkers(\"nameplate\"..i)\n    end\nend\n\n-- Create tables for used markers and enemies to mark\nfunction aura_env.SetupTables()\n    aura_env.usedMarkers = {}\n    aura_env.enemiesToMark1 = {}\n    aura_env.enemiesToMark2 = {}\n    aura_env.enemiesToMark3 = {}\nend",
					["do_custom"] = true,
				},
				["finish"] = {
				},
			},
			["triggers"] = {
				{
					["trigger"] = {
						["duration"] = "1",
						["genericShowOn"] = "showOnCooldown",
						["unit"] = "player",
						["debuffType"] = "HELPFUL",
						["type"] = "custom",
						["names"] = {
						},
						["unevent"] = "auto",
						["subeventPrefix"] = "",
						["spellName"] = 0,
						["event"] = "Cooldown Progress (Spell)",
						["spellIds"] = {
						},
						["realSpellName"] = 0,
						["use_spellName"] = true,
						["custom"] = "function()\n    aura_env.time = aura_env.time or 0\n    if GetTime() >= aura_env.time+0.3 then\n        aura_env.time = GetTime()\n        if not aura_env.enemies then return end\n        \n        -- Trigger the mouseover event on the modifier\n        if aura_env.config.mouseoverSettings.mouseoverKey ~= 1 and aura_env.CheckMouseoverModifier() then\n            WeakAuras.ScanEvents(\"AUTOMARKER_UPDATE_MOUSEOVER\")\n        end\n        \n        aura_env.SetupTables()\n        aura_env.GetUsedMarkers()\n        \n        for i = 1, 40 do\n            local unit = \"nameplate\"..i\n            \n            if aura_env.UnitIsInCombatWithParty(unit) then\n                aura_env.SelectEnemyToMark(unit)\n            end\n        end\n        \n        -- Mark enemies\n        aura_env.MarkEnemies(aura_env.chosenMarkers1, aura_env.enemiesToMark1)\n        aura_env.MarkEnemies(aura_env.chosenMarkers2, aura_env.enemiesToMark2)\n        aura_env.MarkEnemies(aura_env.chosenMarkers3, aura_env.enemiesToMark3)\n    end\nend",
						["custom_type"] = "status",
						["check"] = "update",
						["subeventSuffix"] = "",
