						["custom"] = "function(allstates, event, ...)\n    if event == \"UNIT_SPELLCAST_CHANNEL_START\" then \n        local unit, _, spellID = ...\n        if spellID == 395893 then\n            local guid = UnitGUID(unit)\n            allstates[guid] = {\n                show = true,\n                changed = true,\n                progressType = \"timed\",\n                duration = 2.5,\n                expirationTime = 2.5 + GetTime(),\n                autoHide = true,\n                remaining = 4,\n            }\n            for i = 1,3 do\n                C_Timer.After(2.5*i, function() WeakAuras.ScanEvents(\"CAUSESE_BEDROCK_REPEAT\", 4-i, guid) end)\n            end\n            return true\n        end\n    elseif event == \"CAUSESE_BEDROCK_REPEAT\" and ... then\n        local i, guid = ...\n        allstates[guid] = {\n            show = true,\n            changed = true,\n            progressType = \"timed\",\n            duration = 2.5,\n            expirationTime = 2.5 + GetTime(),\n            remaining = i,\n            autoHide = true,\n        }\n        return true\n    end\nend",
