						["custom"] = "function(allstates, event, id)\n  if not aura_env.config[\"timers\"].primalStorm then return false end\n  if not aura_env.config.OnOff then return false end\n  if event == \"DRAGONFLIGHT_EVENT_TRACKER\" and id == aura_env.id\n  or event == \"STATUS\" or event == \"OPTIONS\"\n  then\n    local regionTimers = {\n      [1] = 1671310800, -- NA\n      [2] = 1670346000, -- KR\n      [3] = 1671303600, -- EU\n      [4] = 1670346000, -- TW\n      [5] = nil -- CN\n    }\n    \n    local firstEvent = regionTimers[GetCurrentRegion()]\n    --Return early if we don't have data on the specific region\n    if(firstEvent == nil) then\n      return\n    end\n    \n    local interval = 10800\n    local duration = 7200\n    local time_to_next = interval - ((GetServerTime() - firstEvent) % interval)\n    local active = interval - time_to_next < duration\n    local remaining = duration - (interval - time_to_next)\n    \n    allstates[\"\"] = {\n      changed = true,\n      show = true,\n      progressType = \"timed\",\n      autoHide = true,\n      duration = active and duration or interval-duration,\n      expirationTime = GetTime() + (active and remaining or time_to_next),\n      active = active\n    }\n    \n    return true\n  end\nend",
						["custom_type"] = "stateupdate",
						["check"] = "event",
						["names"] = {
						},
						["unit"] = "player",
						["customVariables"] = "{\n    active = {\n        display = \"tTigger\",\n        type = \"bool\",\n    }\n}",
