			["actions"] = {
				["start"] = {
				},
				["finish"] = {
				},
				["init"] = {
					["custom"] = "aura_env.zoneID = {\n  [2022] = \"Waking Shores\",\n  [2023] = \"Ohn'aran Plains\",\n  [2024] = \"Azure Span\",\n  [2025] = \"Thaldraszus\",\n  [2085] = \"Primalist Tomorrow\"\n}\n\naura_env.zone = \"Not Active\"\n\naura_env.stormID = {\n  [7252] = \"Frost\",\n  [7256] = \"Frost\",\n  [7260] = \"Frost\",\n  [7224] = \"Frost\",\n  [7228] = \"Frost\",\n  [7244] = \"Frost\",\n  [7232] = \"Frost\",\n  [7236] = \"Frost\",\n  [7240] = \"Frost\",\n  [7248] = \"Frost\",\n  [7301] = \"Frost\",\n}\n\nfunction aura_env.isComplete()\n  if C_QuestLog.IsQuestFlaggedCompleted(70752) then\n    return true\n  end\n  \n  return false\nend\n\n\n\n",
					["do_custom"] = true,
				},
			},
			["triggers"] = {
				{
					["trigger"] = {
						["use_alwaystrue"] = true,
						["use_absorbMode"] = true,
