						["event"] = "Conditions",
						["use_unit"] = true,
						["customDuration"] = "function()\n    return 0, 100, true\nend",
						["subeventPrefix"] = "SPELL",
						["custom"] = "function()\n  -- is this thing even on?\n  if not aura_env.config[\"timers\"].primalStorm then return false end\n  if not aura_env.config.OnOff then return false end\n  if aura_env.config[\"timers\"].hideComplete and aura_env.isComplete() then return false end\n  \n  -- iterate zones\n  for zoneID in pairs(aura_env.zoneID) do\n    \n    -- iterate points of interest for relevant events\n    for _, poi in ipairs(C_AreaPoiInfo.GetAreaPOIForMap(zoneID)) do\n      if aura_env.stormID[poi] and C_AreaPoiInfo.GetAreaPOIInfo(zoneID, poi).isPrimaryMapForPOI then\n        aura_env.zone = aura_env.zoneID[zoneID]\n        return true\n      end  \n    end\n  end\nend",
