						["custom"] = "-- Spy Found - Trigger - CHAT_MSG_MONSTER_SAY\n\nfunction(event, text, _, _, _, target)\n    if event ~= \"CHAT_MSG_MONSTER_SAY\" then\n        return false\n    end\n    if not aura_env then\n        return false\n    end\n    local locale = GetLocale()\n    local language = string.sub(locale, 1, 2)\n    local foundTextLoc = aura_env.foundText[language]\n    if not foundTextLoc then\n        return false\n    end\n    if not string.find(text, foundTextLoc) then\n        return false\n    end\n\n    if aura_env.config.announce_spy_found then\n        local messageEn = aura_env.displayText[\"en\"]\n        local messageLoc = aura_env.displayText[language] or messageEn\n        local message = messageLoc\n        if language ~= \"en\" then\n            message = message .. \" / \" .. messageEn\n        end\n        local chatType = \"SAY\"\n        if IsInLFGDungeon() then\n            chatType = \"INSTANCE_CHAT\"\n        elseif IsInGroup() then\n            chatType = \"PARTY\"\n        end\n        SendChatMessage(message, chatType)\n    end\n\n    local soundID = aura_env.config.spy_found_sound_id\n    if soundID ~= \"0\" then\n        PlaySound(soundID, \"Master\")\n    end\n\n    if aura_env.config.mark_spy_found then\n        local player = UnitName(\"player\")\n        if target == player then\n            SetRaidTarget(\"target\", 8)\n        end\n        return true\n    end\nend",
