			["actions"] = {
				["start"] = {
					["custom"] = "\n\n",
					["do_custom"] = false,
				},
				["init"] = {
					["custom"] = "-- Chatty Rumormonger - On Init\n\nlocal rumorIDs = {\n    --dark vest\n    [45635] = {\n        en=\"dark vest\",\n        de=\"dunkle Weste\",\n    },\n    --light vest\n    [45636] = {\n        en=\"light vest\",\n        de=\"helle Weste\",\n    },\n    --male\n    [45657] = {\n        en=\"male\",\n        de=\"männlich\",\n    },\n    --female\n    [45658] = {\n        en=\"female\",\n        de=\"weiblich\",\n    },\n    --book\n    [45659] = {\n        en=\"book\",\n        de=\"Buch\",\n    },\n    --pouch\n    [45660] = {\n        en=\"pouch\",\n        de=\"Beutel\",\n    },\n    --potion\n    [45666] = {\n        en=\"potion\",\n        de=\"Trank\",\n    },\n    --no potion\n    [45667] = {\n        en=\"no potion\",\n        de=\"kein Trank\",\n    },\n    --no gloves \n    [45672] = {\n        en=\"no gloves\",\n        de=\"keine Handschuhe\",\n    },\n    --gloves\n    [45673] = {\n        en=\"gloves\",\n        de=\"Handschuhe\",\n    },\n    --cape\n    [45674] = {\n        en=\"cape\",\n        de=\"Umhang\",\n    },\n    --no cape\n    [45675] = {\n        en=\"no cape\",\n        de=\"kein Umhang\",\n    },\n    --long sleeves\n    [45676] = {\n        en=\"long sleeves\",\n        de=\"lange Ärmel\",\n    },\n    --short sleeves\n    [45677] = {\n        en=\"short sleeves\",\n        de=\"kurze Ärmel\",\n    },\n}\nlocal clues_found = {}\n\nlocal function ResetClues()\n    clues_found = {}\n    print(\"WeakAura \\\"Court of Stars Helper\\\" clues have been reset\")\nend\naura_env.CourtOfStarsHelper_ResetClues = ResetClues\n\nlocal function OnGossipShow()\n    local options = C_GossipInfo.GetOptions();\n\n    local guid = UnitGUID(\"target\")\n    if not guid then\n        return\n    end\n\n    local _, _, _, _, _, npc_id = strsplit(\"-\", guid)\n    if npc_id ~= \"107486\" then\n        return\n    end\n\n    if not aura_env then\n        return\n    end\n\n    if #options < 1 then\n        return\n    end\n\n    local gossipOptionID = options[1].gossipOptionID\n    C_GossipInfo.SelectOption(gossipOptionID)\n\n    local clue_found = clues_found[gossipOptionID] or false\n    if clue_found and not IsShiftKeyDown() then\n        return\n    end\n    clues_found[gossipOptionID] = true\n\n    local message\n    local rumors = rumorIDs[gossipOptionID]\n    if rumors then\n        local locale = GetLocale()\n        local language = string.sub(locale, 1, 2)\n        message = rumors[language] or rumors[\"en\"]\n        if language ~= \"en\" then\n            message = message .. \" / \" .. rumors[\"en\"]\n        end\n    else\n        message = C_GossipInfo.GetText()\n    end\n\n    local chatType = \"SAY\"\n    if IsInLFGDungeon() then\n        chatType = \"INSTANCE_CHAT\"\n    elseif IsInGroup() then\n        chatType = \"PARTY\"\n    end\n    SendChatMessage(message, chatType)\nend\n\nif aura_env.config.rumor_helper_enable then\n    local frames = {GetFramesRegisteredForEvent(\"GOSSIP_SHOW\")}\n    for _, frame in pairs(frames) do\n        frame:UnregisterEvent(\"GOSSIP_SHOW\")\n    end\n    local rumorHelper = CreateFrame(\"Frame\", \"CourtOfStarsHelper_RumorHelper\")\n    rumorHelper:RegisterEvent(\"GOSSIP_SHOW\")\n    rumorHelper:SetScript(\"OnEvent\", OnGossipShow)\n    for _, frame in pairs(frames) do\n        if frame.name ~= \"CourtOfStarsHelper_RumorHelper\" then\n            frame:RegisterEvent(\"GOSSIP_SHOW\")\n        end\n    end\nend",
					["do_custom"] = true,
				},
				["finish"] = {
					["custom"] = "\n\n",
					["do_custom"] = false,
				},
			},
