						["custom_type"] = "event",
						["custom"] = "-- Chatty Rumormonger - Trigger - CHALLENGE_MODE_START, CHALLENGE_MODE_RESET, CHALLENGE_MODE_COMPLETED\n\nfunction(event)\n    if event ~= \"CHALLENGE_MODE_START\" and event ~= \"CHALLENGE_MODE_RESET\" and event ~= \"CHALLENGE_MODE_COMPLETED\" then\n        return\n    end\n    if not aura_env then\n        return\n    end\n    if not aura_env.CourtOfStarsHelper_ResetClues then\n        print(\"WeakAura \\\"Court of Stars Helper\\\" clues failed to reset\")\n    end\n    aura_env.CourtOfStarsHelper_ResetClues()\nend",
