						["custom"] = "-- Auto Gossip - Trigger - GOSSIP_SHOW\n\nfunction(event)\n    if event ~= \"GOSSIP_SHOW\" then\n        return\n    end\n    local options = C_GossipInfo.GetOptions()\n    if #options < 1 then\n        return\n    end\n    if not aura_env then\n        return\n    end\n    local enabled = aura_env.config.auto_gossip_enable\n    if not enabled then\n        return\n    end\n    local guid = UnitGUID(\"target\") or nil\n    if not guid then\n        guid = UnitGUID(\"mouseover\") or nil\n        if not guid then\n            return\n        end\n    end\n    local _, _, _, _, _, npcID = strsplit(\"-\", guid)\n    local npcs = aura_env.npcs\n    for _, autoGossipID in pairs(npcs) do\n        if tostring(autoGossipID) == npcID then\n            local gossipOptionID = options[1].gossipOptionID\n            C_GossipInfo.SelectOption(gossipOptionID)\n            return\n        end\n    end\nend",
