					["custom"] = "aura_env.regions = {}\n\naura_env.storms = {\n    [1] = \"Air\",\n    [2] = \"Earth\",\n    [3] = \"Fire\",\n    [4] = \"Frost\"\n}\n\naura_env.stormID = {\n    [7249] = \"Air\",\n    [7250] = \"Earth\",\n    [7251] = \"Fire\",\n    [7252] = \"Frost\",\n    \n    [7253] = \"Air\",\n    [7254] = \"Earth\",\n    [7255] = \"Fire\",\n    [7256] = \"Frost\"\n    ,\n    [7257] = \"Air\",\n    [7258] = \"Earth\",\n    [7259] = \"Fire\",\n    [7260] = \"Frost\",\n    \n    [7221] = \"Air\",\n    [7222] = \"Earth\",\n    [7223] = \"Fire\",\n    [7224] = \"Frost\",\n    \n    [7225] = \"Air\",\n    [7226] = \"Earth\",\n    [7227] = \"Fire\",\n    [7228] = \"Frost\",\n    \n    [7241] = \"Air\",\n    [7242] = \"Earth\",\n    [7243] = \"Fire\",\n    [7244] = \"Frost\",\n    \n    [7229] = \"Air\",\n    [7230] = \"Earth\",\n    [7231] = \"Fire\",\n    [7232] = \"Frost\",\n    \n    [7233] = \"Air\",\n    [7234] = \"Earth\",\n    [7235] = \"Fire\",\n    [7236] = \"Frost\",\n    \n    [7237] = \"Air\",\n    [7238] = \"Earth\",\n    [7239] = \"Fire\",\n    [7240] = \"Frost\",\n    \n    [7245] = \"Air\",\n    [7246] = \"Earth\",\n    [7247] = \"Fire\",\n    [7248] = \"Frost\",\n    \n    [7298] = \"Air\",\n    [7299] = \"Earth\",\n    [7300] = \"Fire\",\n    [7301] = \"Frost\",\n}\n\naura_env.zoneID = {\n    [2022] = \"Waking Shores\",\n    [2023] = \"Ohn'aran Plains\",\n    [2024] = \"Azure Span\",\n    [2025] = \"Thaldraszus\"\n}\n\nfunction aura_env.isActive(storm)\n    for zoneID in pairs(aura_env.zoneID) do\n        for _, poi in ipairs(C_AreaPoiInfo.GetAreaPOIForMap(zoneID)) do\n            if aura_env.stormID[poi] and C_AreaPoiInfo.GetAreaPOIInfo(zoneID, poi).isPrimaryMapForPOI then\n                if aura_env.stormID[poi] == storm then\n                    return true\n                end  \n            end\n        end\n    end\n    return false\nend\n\n\n",
