		["Broodkeeper adds locations Mythic"] = {
			["outline"] = "OUTLINE",
			["wagoID"] = "JZfTMMk5M",
			["parent"] = "Broodkeeper Diurna adds timer",
			["displayText_format_p_time_dynamic_threshold"] = 60,
			["customText"] = "function() \n    if aura_env.current and (not aura_env.last or aura_env.last < GetTime() - 0.9) then\n        aura_env.last = GetTime()\n        local currentTime = GetTime() - aura_env.startTime\n        if (currentTime > aura_env.current[1]) then\n            aura_env.index = aura_env.index + 1\n            aura_env.current = aura_env.values[aura_env.index]\n            if (getn(aura_env.values)) then\n                return \"\"\n            end\n        end\n        local returnString = \"\"\n        for i=0,aura_env.config.amount -1 do\n            returnString = returnString .. \" \\n\" .. aura_env.remainingTime(aura_env.index + i,currentTime)\n        end\n        aura_env.lastValue = returnString\n    end\n    \n    \n    if aura_env.current then\n        return aura_env.lastValue\n    else\n        return \"\"\n    end\nend",
			["shadowYOffset"] = -1,
			["anchorPoint"] = "CENTER",
			["displayText_format_p_time_format"] = 0,
			["customTextUpdate"] = "update",
			["automaticWidth"] = "Auto",
			["actions"] = {
				["start"] = {
				},
				["init"] = {
					["custom"] = "aura_env.startTime = GetTime()\naura_env.index = 1\n\naura_env.values = {}\n\n---time in seconds and raid markers for th add spawns\n\naura_env.values[1] = {33,\"{rt4} {rt5}\"}\naura_env.values[2] = {93,\"{rt1}\"}\naura_env.values[3] = {108,\"{rt2}\"}\naura_env.values[4] = {151,\"{rt5}\"}\naura_env.values[5] = {168,\"{rt6}\"}\naura_env.values[6] = {213,\"{rt2}\"}\naura_env.values[7] = {226,\"{rt5}\"}\naura_env.values[8] = {273,\"{rt4}\"}\n\n\n\naura_env.current = aura_env.values[1]\n\n\n--- function to calculate remaining time\naura_env.remainingTime = function(index,time)\n    if (aura_env.values[index]) then\n        local value = aura_env.values[index]\n        local remainingTime = value[1] - time\n        return string.format(\"%02d:%02d \",remainingTime / 60, remainingTime % 60) .. value[2]\n    end\n    return \"\"\nend",
					["do_custom"] = true,
